// // This module implements a 4-to-2 binary decoder with an enable input (en). When enable is high, the decoder outputs a 2-bit signal (y[1:0]) corresponding to the binary value of the 4-bit input (a[3:0]). When enable is low, all outputs should be zero.
module decoder (
  input [1:0] a,
  input en,
  output reg [3:0] y
);always @(*) begin
	if (en) begin
		case (a)
			2'b00: y = 4'b0001;
			2'b01: y = 4'b0010;
			2'b10: y = 4'b0100;
			2'b11: y = 4'b1000;
			default: y = 4'b0000;
		endcase
	end else begin
		y = 4'b0000;
	end
end

endmodule
